rn extracted;\n}\n\nexport function extract(instance: Object, props: Object & { style?: [] | {} }) {\n  return extractProps(propsAndStyles(props), instance);\n}\n\nexport function stringifyPropsForFabric(props: {\n  [key: string]: NumberProp | undefined | null;\n}): { [key: string]: string } {\n  const extracted: { [key: string]: string } = {};\n  Object.keys(props).forEach((k) => {\n    if (props[k] !== undefined && props[k] !== null) {\n      extracted[k] = String(props[k]);\n    }\n  });\n\n  return extracted;\n}\n\nexport function withoutXY(\n  instance: Object,\n  props: Object & { style?: [] | {} },\n) {\n  return extractProps({ ...propsAndStyles(props), x: null, y: null }, instance);\n}\n"],"mappings":"4fAAA,kEACA,sEACA,oDACA,4EACA,wEACA,6BAWA,GAAMA,UAA+C,CAAG,CACtDC,OAAO,CAAE,CAD6C,CAEtDC,OAAO,CAAE,CAF6C,CAAxD,CAKO,QAASC,eAAT,CAAwBC,KAAxB,CAA6D,CAClE,GAAQC,MAAR,CAAkBD,KAAlB,CAAQC,KAAR,CACA,MAAO,CAACA,KAAD,CACHD,KADG,0BAGGE,KAAK,CAACC,OAAN,CAAcF,KAAd,EAAuBG,MAAM,CAACC,MAAP,OAAAD,MAAM,EAAQ,EAAR,yCAAeH,KAAf,GAA7B,CAAqDA,KAHxD,CAIED,KAJF,CAAP,CAMD,CAED,QAASM,UAAT,CAAmBC,MAAnB,CAAoC,CAClC,GAAI,CAACA,MAAL,CAAa,CACX,MAAOC,UAAP,CACD,CACD,GAAMC,QAAO,CAAGF,MAAM,CAACG,KAAP,CAAaC,eAAb,CAAhB,CACA,MAAOF,QAAO,CAAGA,OAAO,CAAC,CAAD,CAAV,CAAgBD,SAA9B,CACD,CAEc,QAASI,aAAT,CACbZ,KADa,CAkBba,GAlBa,CAmBb,CACA,GACEC,GADF,CAaId,KAbJ,CACEc,EADF,CAEEC,OAFF,CAaIf,KAbJ,CAEEe,OAFF,CAGEC,QAHF,CAaIhB,KAbJ,CAGEgB,QAHF,CAIEC,QAJF,CAaIjB,KAbJ,CAIEiB,QAJF,CAKEC,QALF,CAaIlB,KAbJ,CAKEkB,QALF,CAMEC,OANF,CAaInB,KAbJ,CAMEmB,OANF,CAOEC,IAPF,CAaIpB,KAbJ,CAOEoB,IAPF,CAQEb,MARF,CAaIP,KAbJ,CAQEO,MARF,oBAaIP,KAbJ,CASEqB,WATF,CASEA,WATF,6BASgBd,MAThB,qCAaIP,KAbJ,CAUEsB,SAVF,CAUEA,SAVF,2BAUcf,MAVd,mCAaIP,KAbJ,CAWEuB,SAXF,CAWEA,SAXF,2BAWchB,MAXd,kBAYEiB,SAZF,CAaIxB,KAbJ,CAYEwB,SAZF,CAcA,GAAMC,UAAyB,CAAG,EAAlC,CAEA,GAAMC,UAAmB,CAAG,EAA5B,CACA,GAAAC,yBAAA,EAAiBF,SAAjB,CAA4BzB,KAA5B,CAAmCa,GAAnC,EACA,GAAAe,oBAAA,EAAYH,SAAZ,CAAuBzB,KAAvB,CAA8B0B,SAA9B,EACA,GAAAG,sBAAA,EAAcJ,SAAd,CAAyBzB,KAAzB,CAAgC0B,SAAhC,EAE